from itertools import combinations

class Solution:
    def minimumDifference(self, nums, k):
        if k == 1:
            return 0
        best = None
        for combo in combinations(nums, k):
            diff = max(combo) - min(combo)
            if best is None or diff < best:
                best = diff
        return best

