class Solution:
    def minimumDifference(self, nums, k):
        if k == 1:
            return 0
        nums = sorted(nums)
        best = float('inf')
        for i in range(len(nums) - k + 1):
            diff = nums[i + k - 1] - nums[i]
            if diff < best:
                best = diff
        return best

