var minimumDifference = function(nums, k) {
    if (k === 1) return 0;
    const sorted = nums.slice().sort((a, b) => a - b);
    let best = Infinity;
    for (let i = 0; i <= sorted.length - k; i++) {
        const diff = sorted[i + k - 1] - sorted[i];
        if (diff < best) best = diff;
    }
    return best;
};
